#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int m, n, W, P, x, y;
        scanf("%d %d %d %d %d %d", &m, &n, &W, &P, &x, &y);
        int farm[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                farm[i][j] = 0;
            }
        }
        farm[0][0] = x;
        farm[m - 1][n - 1] = y;
        for (int week = 0; week < W; week++) {
            int newFarm[m][n];
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    newFarm[i][j] = 0;
                }
            }
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    int watermelons = farm[i][j];
                    if (watermelons >= P) {
                        watermelons %= P;
                    }
                    newFarm[i][j] += watermelons;
                    if (i > 0) newFarm[i - 1][j] += watermelons;
                    if (i < m - 1) newFarm[i + 1][j] += watermelons;
                    if (j > 0) newFarm[i][j - 1] += watermelons;
                    if (j < n - 1) newFarm[i][j + 1] += watermelons;
                    if (i > 0 && j > 0) newFarm[i - 1][j - 1] += watermelons;
                    if (i > 0 && j < n - 1) newFarm[i - 1][j + 1] += watermelons;
                    if (i < m - 1 && j > 0) newFarm[i + 1][j - 1] += watermelons;
                    if (i < m - 1 && j < n - 1) newFarm[i + 1][j + 1] += watermelons;
                }
            }
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    farm[i][j] = newFarm[i][j];
                }
            }
        }
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                printf("%d ", farm[i][j]);
            }
            printf("\n");
        }
        printf("\n");
    }
    return 0;
}

